"use client";

import Link from "next/link";
import Image from "next/image";
import { useState, useEffect } from "react";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faTrash, faShoppingCart } from "@fortawesome/free-solid-svg-icons";
import styles from "./cart.module.scss";

export default function CartPage() {
  const [cartItems, setCartItems] = useState([]);
  const [totalPrice, setTotalPrice] = useState(0);

  useEffect(() => {
    const savedCart = localStorage.getItem("cart");
    if (savedCart) {
      setCartItems(JSON.parse(savedCart));
    }
  }, []);

  useEffect(() => {
    setTotalPrice(
      cartItems.reduce((total, item) => total + item.price * item.quantity, 0)
    );
    localStorage.setItem("cart", JSON.stringify(cartItems));
  }, [cartItems]);

  const handleQuantityChange = (itemId, newQuantity) => {
    setCartItems((prevItems) =>
      prevItems.map((item) =>
        item.id === itemId ? { ...item, quantity: Math.max(1, newQuantity) } : item
      )
    );
  };

  const handleRemoveItem = (itemId) => {
    setCartItems((prevItems) => prevItems.filter((item) => item.id !== itemId));
  };

  const handleClearCart = () => {
    setCartItems([]);
  };

  const handleNoteChange = (itemId, note) => {
    setCartItems((prevItems) =>
      prevItems.map((item) => (item.id === itemId ? { ...item, note } : item))
    );
  };

  return (
    <div className={styles.cartContainer}>
      <h1>
        <FontAwesomeIcon icon={faShoppingCart} /> Giỏ hàng của bạn (
        {cartItems.length} sản phẩm)
      </h1>
      {cartItems.length === 0 ? (
        <div className={styles.emptyCart}>
          <p>Giỏ hàng của bạn đang trống.</p>
          <Link href="/">Tiếp tục mua sắm</Link>
        </div>
      ) : (
        <div className={styles.cartItems}>
          {cartItems.map((item) => (
            <div key={item.id} className={styles.cartItem}>
              <Image
                src={item.image}
                alt={item.name}
                width={80}
                height={80}
                className={styles.itemImage}
              />
              <div className={styles.itemInfo}>
                <p className={styles.itemName}>{item.name}</p>
                <p className={styles.itemPrice}>{item.price.toLocaleString()} VNĐ</p>
                <textarea
                  className={styles.itemNote}
                  placeholder="Ghi chú cho sản phẩm..."
                  value={item.note || ""}
                  onChange={(e) => handleNoteChange(item.id, e.target.value)}
                />
              </div>
              <div className={styles.quantityControls}>
                <button
                  onClick={() => handleQuantityChange(item.id, item.quantity - 1)}
                  disabled={item.quantity <= 1}
                >
                  -
                </button>
                <span>{item.quantity}</span>
                <button onClick={() => handleQuantityChange(item.id, item.quantity + 1)}>
                  +
                </button>
              </div>
              <p className={styles.itemTotal}>
                {(item.price * item.quantity).toLocaleString()} VNĐ
              </p>
              <FontAwesomeIcon
                icon={faTrash}
                onClick={() => handleRemoveItem(item.id)}
                className={styles.deleteIcon}
              />
            </div>
          ))}
        </div>
      )}
      <div className={styles.cartFooter}>
        <strong>Tổng cộng: {totalPrice.toLocaleString()} VNĐ</strong>
        <div> {/* Added container for buttons */}
          <button
            className={styles.checkoutButton}
            disabled={cartItems.length === 0}
          >
            Thanh toán
          </button>
          <button
            className={styles.clearCartButton}
            onClick={handleClearCart}
            disabled={cartItems.length === 0}
          >
            Xóa tất cả
          </button>
        </div>
      </div>
    </div>
  );
}